    return true;
  }

  if (hasMain && hasVersion && !hasServerScript && (hasLibKeyword || hasPeerDeps || hasExamplesDir)) {
    return true;
  }

  if (hasExamplesDir && hasTestDir && !hasServerScript && !hasAppsDir) {
    return true;
  }

  if (WELL_KNOWN_CLIENT_LIBS.test(baseName) && !hasServerScript) {
    return true;
  }

